import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: "Paris Saint-Germain FC vs. Liverpool FC",
      outcomes: [
        "Will Paris Saint-Germain FC win on 2026-04-08?",
        "Will Paris Saint-Germain FC vs. Liverpool FC end in a draw?",
        "Will Liverpool FC win on 2026-04-08?"
      ]
    }
  });

  const rows = Array.isArray(result?.matchedOutcomes) ? result.matchedOutcomes : [];
  const outcomes = rows.map((row) => ({
    matchedName: row.matchedName,
    currentPrice: row.currentPrice,
    impliedProbability: row.impliedProbability,
    bestBid: row.bestBid,
    bestAsk: row.bestAsk,
    spread: row.spread,
    spreadCentsDisplay: row.spreadCentsDisplay,
    spreadPercentDisplay: row.spreadPercentDisplay,
    readableQuote: row.readableQuote
  }));

  return {
    eventTitle: result?.eventTitle,
    eventSlug: result?.eventSlug,
    selectedOutcomes: outcomes,
    unmatchedOutcomes: Array.isArray(result?.unmatchedOutcomes) ? result.unmatchedOutcomes : [],
    widestSpreadOutcome: result?.widestSpreadOutcome,
    fetchedAt: result?.fetchedAt,
    synthesisHint: result?.synthesisHint
  };
}

