export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      eventQuery: "Paris Saint-Germain FC vs. Liverpool FC"
    }
  });

  const discoveredOutcomes = Array.isArray(discovery?.outcomes)
    ? discovery.outcomes
    : Array.isArray(discovery?.matchedOutcomes)
      ? discovery.matchedOutcomes
      : Array.isArray(discovery?.results)
        ? discovery.results
        : [];

  const normalized = discoveredOutcomes
    .map((row) => row?.name || row?.title || row?.outcome || row?.matchedName)
    .filter(Boolean);

  const candidateOutcomes = [
    normalized.find((name) => /paris saint-germain/i.test(name) && /win|yes|to qualify|to advance/i.test(name)) || "Will Paris Saint-Germain FC win on 2026-04-08?",
    normalized.find((name) => /draw|tie/i.test(name)) || "Will Paris Saint-Germain FC vs. Liverpool FC end in a draw?",
    normalized.find((name) => /liverpool/i.test(name) && /win|yes|to qualify|to advance/i.test(name)) || "Will Liverpool FC win on 2026-04-08?"
  ];

  const result = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: "Paris Saint-Germain FC vs. Liverpool FC",
      outcomes: candidateOutcomes
    }
  });

  const rows = Array.isArray(result?.matchedOutcomes) ? result.matchedOutcomes : [];
  const outcomes = rows.map((row) => ({
    matchedName: row.matchedName,
    currentPrice: row.currentPrice,
    impliedProbability: row.impliedProbability,
    bestBid: row.bestBid,
    bestAsk: row.bestAsk,
    spread: row.spread,
    spreadCentsDisplay: row.spreadCentsDisplay,
    spreadPercentDisplay: row.spreadPercentDisplay,
    readableQuote: row.readableQuote
  }));

  return {
    eventTitle: result?.eventTitle,
    eventSlug: result?.eventSlug,
    selectedOutcomes: outcomes,
    unmatchedOutcomes: Array.isArray(result?.unmatchedOutcomes) ? result.unmatchedOutcomes : [],
    widestSpreadOutcome: result?.widestSpreadOutcome,
    fetchedAt: result?.fetchedAt,
    synthesisHint: result?.synthesisHint
  };
}

