      maxOutcomes: 20
    }
  });

  const wanted = new Set([
    "Spain",
    "France",
    "England",
    "Switzerland",
    "New Zealand",
    "South Korea"
  ]);

  const sampled = Array.isArray(result?.whalesByOutcome)
    ? result.whalesByOutcome.filter((row) => wanted.has(row?.outcome))
    : [];

  let strongest = null;
  for (const row of sampled) {
    const value = typeof row?.totalWhaleValue === "number" ? row.totalWhaleValue : null;
    if (value === null) continue;
    if (!strongest || value > strongest.totalWhaleValue) {
      strongest = row;
    }
  }

  return {
    eventTitle: result?.eventTitle,
    eventSlug: result?.eventSlug,
    fetchedAt: result?.fetchedAt,
    sampledOutcomes: sampled.map((row) => ({
      rank: row.rank,
      outcome: row.outcome,
      whaleCount: row.whaleCount,
      totalWhaleValue: row.totalWhaleValue,
      topWhalePosition: row.topWhalePosition,
      convictionLevel: row.convictionLevel,
      currentPrice: row.currentPrice
    })),
    strongestWhaleBacking: strongest
      ? {
          outcome: strongest.outcome,
          totalWhaleValue: strongest.totalWhaleValue,
          whaleCount: strongest.whaleCount,
          convictionLevel: strongest.convictionLevel
        }
      : null
  };
}

