    toolId,
    toolName: "get_event_live_volume",
    args: {
      eventQuery: "Within the 'Iran x Israel/US conflict ends by...?' event, which date buckets are taking the biggest share of live trading right now, especially 'Iran x Israel/US conflict ends by April 15?' versus 'Iran x Israel/US conflict ends by April 30?' and 'Iran x Israel/US conflict ends by June 30?'"
    }
  });

  const markets = Array.isArray(result?.markets) ? result.markets : [];
  const normalized = markets
    .map((m) => ({
      title: m?.title ?? "",
      conditionId: m?.conditionId ?? m?.market ?? "",
      value: typeof m?.value === "number" ? m.value : null,
      shareOfEventTotal: typeof m?.shareOfEventTotal === "number" ? m.shareOfEventTotal : null
    }))
    .filter((m) => m.title || m.conditionId);

  const focusTitles = [
    "April 15",
    "April 30",
    "June 30"
  ];

  const focusMatches = normalized.filter((row) =>
    focusTitles.some((t) => row.title.includes(t))
  );

  return {
    eventTitle: result?.eventTitle ?? null,
    eventId: result?.eventId ?? null,
    volumeBreakdownAvailable: result?.volumeBreakdownAvailable ?? false,
    selectionReason: result?.selectionReason ?? null,
    warning: result?.warning ?? null,
    fetchedAt: result?.fetchedAt ?? null,
    topLiveTradingBuckets: normalized
      .sort((a, b) => (b.shareOfEventTotal ?? -1) - (a.shareOfEventTotal ?? -1))
      .slice(0, 10),
    focusBuckets: focusMatches.sort((a, b) => (b.shareOfEventTotal ?? -1) - (a.shareOfEventTotal ?? -1)),
    rawCount: markets.length
  };
}

