import { callMcpSkill } from "@/lib/ai/skills/mcp";

const TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  const marketQuery = "Iran x Israel/US conflict ends by April 15?";

  const [liquidity, efficiency] = [
    await callMcpSkill({
      toolId: TOOL_ID,
      toolName: "analyze_market_liquidity",
      args: { marketQuery }
    }),
    await callMcpSkill({
      toolId: TOOL_ID,
      toolName: "check_market_efficiency",
      args: { marketQuery }
    })
  ];

  const spreadObj = liquidity.spread || {};
  const outcomes = Array.isArray(efficiency.outcomes) ? efficiency.outcomes : [];
  const truePct = efficiency.trueProbabilitiesPercent || {};
  const trueProbabilities = efficiency.trueProbabilities || {};

  const implied = outcomes.map((o) => ({
    name: o?.name,
    price: o?.price,
    tokenId: o?.tokenId,
    impliedProbability: o?.impliedProbability,
    impliedProbabilityPercent: o?.impliedProbabilityPercent,
    vigAdjustedProbabilityPercent:
      truePct?.[o?.name] ?? null,
    vigAdjustedProbability:
      trueProbabilities?.[o?.name] ?? null
  }));

  return {
    market: liquidity.market,
    fetchedAt: {
      liquidity: liquidity.fetchedAt,
      efficiency: efficiency.fetchedAt
    },
    quote: {
      bestBid: spreadObj.bestBid ?? null,
      bestAsk: spreadObj.bestAsk ?? null,
      midpoint: typeof liquidity.currentPrice === "number" ? liquidity.currentPrice : null,
      spread: spreadObj.absolute ?? spreadObj.spreadCents ?? spreadObj.bps ?? null,
      spreadBps: spreadObj.bps ?? spreadObj.spreadBps ?? null,
      spreadPercent: spreadObj.percentage ?? null
    },
    vigAdjustedImpliedProbabilities: implied,
    marketEfficiency: efficiency.marketEfficiency,
    selectionReason: efficiency.selectionReason,
    recommendation: liquidity.recommendation
  };
}

