export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: "US x Iran ceasefire by ...?",
      sortBy: "volume"
    }
  });

  const eventTitle = discovery?.eventTitle;
  const eventSlug = discovery?.eventSlug;
  const eventUrl = discovery?.eventUrl;
  const outcomes = Array.isArray(discovery?.outcomes) ? discovery.outcomes : [];

  const liveBuckets = outcomes.filter((o) => {
    const name = String(o?.name || "");
    return /\b(by|before|after)\b/i.test(name);
  });

  const rankedByProbability = [...liveBuckets].sort((a, b) => (Number(b?.price) || 0) - (Number(a?.price) || 0));
  const rankedByVolume = [...liveBuckets].sort((a, b) => (Number(b?.volume) || 0) - (Number(a?.volume) || 0));

  return {
    eventTitle,
    eventSlug,
    eventUrl,
    totalOutcomes: outcomes.length,
    liveBucketsCount: liveBuckets.length,
    liveBuckets: liveBuckets.map((o) => ({
      name: o?.name,
      price: o?.price,
      pricePercent: o?.pricePercent,
      volume: o?.volume,
      tokenId: o?.tokenId,
      conditionId: o?.conditionId
    })),
    highestQuotedProbability: rankedByProbability[0]
      ? {
          name: rankedByProbability[0].name,
          price: rankedByProbability[0].price,
          pricePercent: rankedByProbability[0].pricePercent,
          volume: rankedByProbability[0].volume
        }
      : null,
    mostVolume: rankedByVolume[0]
      ? {
          name: rankedByVolume[0].name,
          price: rankedByVolume[0].price,
          pricePercent: rankedByVolume[0].pricePercent,
          volume: rankedByVolume[0].volume
        }
      : null,
    note:
      "If you want, I can do a second pass on the exact event slug to verify which buckets are still live versus expired using the event metadata."
  };
}

